import React from "react";
import { Box, Chip, Divider, Typography } from "@mui/material";
import List from '@mui/material/List';
import ListItem from '@mui/material/ListItem';
import ListItemText from '@mui/material/ListItemText';
import ListItemAvatar from '@mui/material/ListItemAvatar';
import Avatar from '@mui/material/Avatar';
import ContactMailIcon from '@mui/icons-material/ContactMail';
import WorkIcon from '@mui/icons-material/Work';
import SchoolIcon from '@mui/icons-material/School';
import BadgeIcon from '@mui/icons-material/Badge';
import VisibilityIcon from '@mui/icons-material/Visibility';
import VisibilityOffIcon from '@mui/icons-material/VisibilityOff';
import PreviewIcon from '@mui/icons-material/Preview';
import { GetUserEmail } from "@/utils/token";
import { ProfileResult } from "@/types/profile.types";
import { ProfileInfoDialog } from '@/components/ProfileInfoDialog';
import { compactChipSx } from '@/constants/ThemeConstants';

export const ProfileDisplay = (props: ProfileResult) => {
    const [previewOpen, setPreviewOpen] = React.useState(false);
    const visibilityChip = (visible: boolean) => (
        <Chip
            icon={visible ? <VisibilityIcon sx={{ fontSize: '0.85rem' }} /> : <VisibilityOffIcon sx={{ fontSize: '0.85rem' }} />}
            label={visible ? "Visible to members" : "Not visible to anyone"}
            size="small"
            variant="outlined"
            sx={{ ...compactChipSx }}
        />
    );

    return (
        <>
            <List >
                <ListItem>
                    <ListItemAvatar>
                        <Avatar>
                            <BadgeIcon />
                        </Avatar>
                    </ListItemAvatar>
                    <ListItemText primary="Navodaya Info" secondary={visibilityChip(true)} slotProps={{ secondary: { component: "div" } }} />
                </ListItem>
                <ListItem>
                    <div>
                        <span>
                            <b>Name:</b> {props.name}
                        </span>
                        <br />
                        <span>
                            <b>{props.profileType}:</b> {props.entryYear} - {props.exitYear === 0 ? "Present" : props.exitYear}
                        </span>
                        <br />
                        <span>
                            <b>Association:</b> {props.firstJnvName}{props.otherJnvNames ? `, ${props.otherJnvNames}` : ""}
                        </span>
                    </div>
                </ListItem>
                <Divider />
                <ListItem>
                    <ListItemAvatar>
                        <Avatar>
                            <ContactMailIcon />
                        </Avatar>
                    </ListItemAvatar>
                    <ListItemText primary="Contact Info" secondary={visibilityChip(props.isContactInfoVisible)} slotProps={{ secondary: { component: "div" } }} />
                </ListItem>
                <ListItem>
                    <div>
                        <span>
                            <b>Email:</b> {props.email ?? GetUserEmail()}
                        </span>
                        <br />
                        <span>
                            <b>Phone:</b> {props.phone}
                        </span>
                        <br />
                        <span>
                            <b>Location:</b> {props.location}
                        </span>
                    </div>
                </ListItem>
                <Divider />
                <ListItem>
                    <ListItemAvatar>
                        <Avatar>
                            <SchoolIcon />
                        </Avatar>
                    </ListItemAvatar>
                    <ListItemText primary="Education Info" secondary={visibilityChip(props.isHigherEducationInfoVisible)} slotProps={{ secondary: { component: "div" } }} />
                </ListItem>
                <ListItem>
                    <div>
                        <span>
                            <b>University:</b> {props.university}
                        </span>
                        <br />
                        <span>
                            <b>Degree:</b> {props.degree}
                        </span>
                    </div>
                </ListItem>
                <Divider />
                <ListItem>
                    <ListItemAvatar>
                        <Avatar>
                            <WorkIcon />
                        </Avatar>
                    </ListItemAvatar>
                    <ListItemText primary="Work Info" secondary={visibilityChip(props.isEmploymentInfoVisible)} slotProps={{ secondary: { component: "div" } }} />
                </ListItem>
                <ListItem>
                    <div>
                        <span>
                            <b>Job Title:</b> {props.jobTitle}
                        </span>
                        <br />
                        <span>
                            <b>organisation:</b> {props.organisation}
                        </span>
                    </div>
                </ListItem>
                <Divider />
                <ListItem>
                    <Box
                        onClick={() => setPreviewOpen(true)}
                        sx={{ display: 'flex', alignItems: 'center', gap: 0.75, cursor: 'pointer', py: 1, color: 'primary.main', '&:hover': { textDecoration: 'underline' } }}
                    >
                        <PreviewIcon sx={{ fontSize: '1.2rem' }} />
                        <Typography variant="body2" sx={{ fontWeight: 500 }}>
                            Preview how others see my profile
                        </Typography>
                    </Box>
                </ListItem>
            </List>

            <ProfileInfoDialog
                open={previewOpen}
                profileId={props.id}
                mode="public"
                onClose={() => setPreviewOpen(false)}
            />
        </>
    );
};

